import { CommonModule, DOCUMENT } from '@angular/common';
import { Component, HostListener, Inject, Input, OnChanges, OnDestroy, SimpleChanges } from '@angular/core';
import { DomSanitizer, SafeResourceUrl } from '@angular/platform-browser';
import { ArtworkGalleryItem, ArtworkMainImage, ArtworkVideo } from '../../interfaces/artwork.interface';
import { SiteLanguage } from '../../interfaces/language.interface';

interface ArtworkGalleryViewImageItem {
  kind: 'image';
  src: string;
  zoomSrc: string;
  thumbnailSrc: string;
  alt: string;
  description: string;
}

interface ArtworkGalleryViewVideoItem {
  kind: 'video';
  videoType: ArtworkVideo['type'];
  thumbnailSrc: string;
  alt: string;
  description: string;
  url: string;
  embedUrl: string;
}

type ArtworkGalleryViewItem = ArtworkGalleryViewImageItem | ArtworkGalleryViewVideoItem;

@Component({
  selector: 'app-artwork-gallery',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './artwork-gallery.component.html',
  styleUrl: './artwork-gallery.component.sass'
})
export class ArtworkGalleryComponent implements OnChanges, OnDestroy {
  private readonly imageOrientations = new Map<string, 'portrait' | 'landscape'>();
  private fullscreenScrollY = 0;

  constructor(
    private readonly sanitizer: DomSanitizer,
    @Inject(DOCUMENT) private readonly document: Document
  ) {}

  @Input({ required: true }) mainImage!: ArtworkMainImage;
  @Input({ required: true }) galleryItems: ArtworkGalleryItem[] = [];
  @Input({ required: true }) language!: SiteLanguage;
  @Input() video: ArtworkVideo | null = null;
  @Input() variant: 'default' | 'product' = 'default';
  @Input() showHeader = true;
  protected selectedIndex = 0;
  protected zoomActive = false;
  protected zoomX = 50;
  protected zoomY = 50;
  protected fullscreenOpen = false;
  protected readonly zoomScale = 8;

  protected get items(): ArtworkGalleryViewItem[] {
    const gallery = this.galleryItems.map((item) => ({
      kind: 'image' as const,
      src: item.sources.large || item.sources.medium || item.sources.small,
      zoomSrc: item.sources.original || item.sources.large || item.sources.medium || item.sources.small,
      thumbnailSrc: item.sources.thumbnail || item.sources.small || item.sources.large,
      alt: item.description[this.language] || item.description.it,
      description: item.description[this.language] || item.description.it
    }));

    const items: ArtworkGalleryViewItem[] = [
      {
        kind: 'image',
        src: this.mainImage.sources.large || this.mainImage.sources.medium || this.mainImage.sources.small,
        zoomSrc: this.mainImage.sources.original || this.mainImage.sources.large || this.mainImage.sources.medium || this.mainImage.sources.small,
        thumbnailSrc: this.mainImage.sources.thumbnail || this.mainImage.sources.small || this.mainImage.sources.large,
        alt: this.mainImage.alt[this.language] || this.mainImage.alt.it,
        description: this.mainImage.alt[this.language] || this.mainImage.alt.it
      },
      ...gallery
    ];

    if (this.video) {
      items.push({
        kind: 'video',
        videoType: this.video.type,
        thumbnailSrc: this.mainImage.sources.thumbnail || this.mainImage.sources.small || this.mainImage.sources.large,
        alt: this.language === 'it' ? 'Video dell’opera' : 'Artwork video',
        description: this.language === 'it' ? 'Video dell’opera' : 'Artwork video',
        url: this.video.url,
        embedUrl: this.video.embedUrl
      });
    }

    return items;
  }

  protected get selectedImageItem(): ArtworkGalleryViewImageItem | null {
    return this.selectedItem?.kind === 'image' ? this.selectedItem : null;
  }

  protected get selectedVideoItem(): ArtworkGalleryViewVideoItem | null {
    return this.selectedItem?.kind === 'video' ? this.selectedItem : null;
  }

  protected get shouldShowThumbnails(): boolean {
    return this.items.length > 1;
  }

  protected get selectedImageOrientation(): 'portrait' | 'landscape' {
    if (!this.selectedImageItem) {
      return 'landscape';
    }

    return this.imageOrientations.get(this.selectedImageItem.zoomSrc || this.selectedImageItem.src) || 'landscape';
  }

  protected get shouldUsePortraitGalleryStage(): boolean {
    return this.variant === 'product' && this.shouldShowThumbnails && this.selectedImageOrientation === 'portrait';
  }

  protected get zoomBackgroundSize(): string {
    return `${this.zoomScale * 100}% auto`;
  }

  protected get trustedEmbedUrl(): SafeResourceUrl | null {
    const video = this.selectedVideoItem;

    if (!video || video.videoType !== 'youtube') {
      return null;
    }

    return this.sanitizer.bypassSecurityTrustResourceUrl(video.embedUrl);
  }

  protected get isEmbeddableVideo(): boolean {
    return this.selectedVideoItem?.videoType === 'youtube';
  }

  protected get selectedItem(): ArtworkGalleryViewItem | null {
    return this.items[this.selectedIndex] || this.items[0] || null;
  }

  @HostListener('document:keydown.escape')
  protected onEscape(): void {
    if (this.fullscreenOpen) {
      this.closeFullscreen();
    }
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['mainImage'] || changes['galleryItems'] || changes['video']) {
      this.selectedIndex = 0;
      this.zoomActive = false;
      this.setFullscreen(false);
    }
  }

  ngOnDestroy(): void {
    this.setFullscreen(false);
  }

  protected selectItem(index: number): void {
    this.selectedIndex = index;
    this.zoomActive = false;
  }

  protected trackImageOrientation(event: Event, item: ArtworkGalleryViewImageItem): void {
    const image = event.target as HTMLImageElement | null;
    if (!image?.naturalWidth || !image.naturalHeight) {
      return;
    }

    this.imageOrientations.set(
      item.zoomSrc || item.src,
      image.naturalHeight > image.naturalWidth ? 'portrait' : 'landscape'
    );
  }

  protected openFullscreen(): void {
    if (this.variant !== 'product' || !this.selectedImageItem) {
      return;
    }

    this.setFullscreen(true);
    this.zoomActive = false;
  }

  protected closeFullscreen(): void {
    this.setFullscreen(false);
  }

  protected activateZoom(): void {
    if (this.variant !== 'product' || !this.selectedImageItem) {
      return;
    }

    this.zoomActive = true;
  }

  protected deactivateZoom(): void {
    this.zoomActive = false;
  }

  protected updateZoomPosition(event: MouseEvent): void {
    if (this.variant !== 'product' || !this.selectedImageItem) {
      return;
    }

    const target = event.currentTarget as HTMLElement | null;
    if (!target) {
      return;
    }

    const rect = target.getBoundingClientRect();
    const relativeX = ((event.clientX - rect.left) / rect.width) * 100;
    const relativeY = ((event.clientY - rect.top) / rect.height) * 100;

    this.zoomX = Math.max(0, Math.min(100, relativeX));
    this.zoomY = Math.max(0, Math.min(100, relativeY));
  }

  private setFullscreen(open: boolean): void {
    this.fullscreenOpen = open;

    const body = this.document.body;
    const html = this.document.documentElement;
    const windowRef = this.document.defaultView;

    if (open) {
      this.fullscreenScrollY = windowRef?.scrollY || 0;
      body.classList.add('artwork-fullscreen-open');
      html.classList.add('artwork-fullscreen-open');
      body.style.position = 'fixed';
      body.style.top = `-${this.fullscreenScrollY}px`;
      body.style.left = '0';
      body.style.right = '0';
      body.style.width = '100%';
      html.style.overflow = 'hidden';
      return;
    }

    body.classList.remove('artwork-fullscreen-open');
    html.classList.remove('artwork-fullscreen-open');
    body.style.position = '';
    body.style.top = '';
    body.style.left = '';
    body.style.right = '';
    body.style.width = '';
    html.style.overflow = '';

    if (windowRef) {
      windowRef.scrollTo({ top: this.fullscreenScrollY, left: 0, behavior: 'auto' });
    }
  }
}
